### Date Utilities

Date manipulation and formatting using date-fns.

```typescript
import { formatDate, setDefaultDateLocale, ms } from '@belt/tools';
import { ptBR } from 'date-fns/locale';

// Format dates
formatDate(new Date(), 'yyyy-MM-dd'); // '2026-01-14'
formatDate(new Date(), 'MMM dd, yyyy'); // 'Jan 14, 2026'
formatDate('2026-01-14', 'dd/MM/yyyy'); // '14/01/2026'

// Set global locale
setDefaultDateLocale(ptBR);
formatDate(new Date(), 'MMMM'); // 'janeiro'

// Override locale for single call
import { enUS } from 'date-fns/locale';
formatDate(new Date(), 'MMMM', { locale: enUS }); // 'January'

// Time string conversion
ms('1s');       // 1000
ms('5m');       // 300000
ms('1h');       // 3600000
ms('2d');       // 172800000
ms('1w');       // 604800000
ms('1mo');      // ~2629800000
ms('1y');       // ~31557600000
ms('500ms');    // 500

// Use in configs
const CACHE_TTL = ms('5m');
const DEBOUNCE = ms('300ms');
const POLL_INTERVAL = ms('30s');
```

**Supported time units:** `ms`, `s`, `m`/`min`, `h`, `d`, `w`, `mo`/`mon`/`months`, `y`

---

### Object Utilities

Type-safe object manipulation with deep path access.

```typescript
import {
  getProperty,
  setProperty,
  objectKeys,
  objectEntries,
  objectValues,
  keyBy,
  isObject,
  assertObject,
  requireAll,
  deepFreeze,
} from '@belt/tools';

// Deep property access (type-safe)
const street = getProperty(user, 'address.street');
const city = getProperty(user, 'address.city', true); // Allow falsy values

// Set nested properties
setProperty(train, 'metadata.lastInspection', new Date());

// Object manipulation
const keys = objectKeys(train); // Type-safe keys
const entries = objectEntries(train); // Typed entries
const values = objectValues(train); // Typed values

// Array to object by key
const trainsById = keyBy(trains, 'id');
// Or with function
const trainsByName = keyBy(trains, (t) => t.name);

// Type guards
if (isObject(value)) {
  // value is UnknownRecord
}

// Assert object with no falsy values
const validated = requireAll({
  id: train.id,
  name: train.name,
  mileage: train.mileage,
});

// Deep freeze (immutability)
const frozen = deepFreeze(config);
```

**Path Examples:**
```typescript
type User = {
  id: string;
  profile: {
    address: {
      street: string;
      city: string;
    };
  };
};

// All paths are type-checked
getProperty(user, 'id');                    // ✓ string
getProperty(user, 'profile.address.city');  // ✓ string
getProperty(user, 'profile.invalid');       // ✗ Type error
```

---

### String Utilities

String manipulation with type inference.

```typescript
import { capitalize, isString, assertString } from '@belt/tools';

// Capitalize
capitalize('hello'); // 'Hello' (type: 'Hello')

// Type guards
if (isString(value)) {
  console.log(value.toUpperCase());
}

// Assertions
assertString(value);
assertString(value, { notEmpty: true });
assertString(value, { message: 'Name is required', notEmpty: true });
```

---

### Error Handling

Comprehensive error utilities with stack trace management.

```typescript
import {
  invariant,
  tryCatch,
  InvariantError,
  createErrorList,
} from '@belt/tools';

// Assertions
invariant(user.id, 'User ID is required');
invariant(trains.length > 0, 'No trains found');

// Safe error handling
const [error, result] = tryCatch(() => JSON.parse(data));
if (error) {
  console.error('Parse failed:', error.message);
} else {
  console.log('Success:', result);
}

// Collect multiple errors
const errors = createErrorList('Validation failed: ');
if (!train.id) errors.add('Missing ID');
if (!train.name) errors.add('Missing name');
if (train.mileage < 0) errors.add('Invalid mileage');
errors.check(); // Throws if any errors
```

---

### Type Utilities

Advanced TypeScript type helpers.

```typescript
import type {
  Paths,          // All dot-notation paths of object
  PathType,       // Type at specific path
  Compute,        // Flatten intersection types
  Writable,       // Remove readonly modifiers
  Falsy,          // Union of falsy values
  InferType,      // Infer type from schema
  UnknownRecord,  // { [key: string]: unknown }
  AnyRecord,      // { [key: string]: any }
  MaybePromise,   // T | Promise<T>
  MaybeArray,     // T | T[]
  PromiseValue,   // Extract Promise<T> → T
  Simplify,       // Flatten complex types
  Merge,          // Deep merge two types
  PartialFields,  // Make specific fields optional
  NullableToPartial, // Convert nullable to optional
  UnionToIntersection, // Union → Intersection
  CastUnknown,    // Cast if unknown
  SerializableOnly, // Only serializable fields
} from '@belt/tools';

// Example: Paths
type User = {
  id: string;
  profile: {
    address: {
      street: string;
    };
  };
};

type UserPaths = Paths<User>;
// 'id' | 'profile' | 'profile.address' | 'profile.address.street'

type StreetType = PathType<User, 'profile.address.street'>;
// string

// Example: Compute (flatten intersections)
type A = { a: number };
type B = { b: string };
type Flat = Compute<A & B>; // { a: number; b: string }

// Example: Writable
type ReadOnly = { readonly id: string; readonly name: string };
type Mutable = Writable<ReadOnly>; // { id: string; name: string }

// Example: PartialFields
type Train = { id: string; name: string; metadata: object };
type Optional = PartialFields<Train, ['metadata']>;
// { id: string; name: string; metadata?: object }
```

**Type Guards:**
```typescript
import { isFalsy } from '@belt/tools';
import type { Falsy } from '@belt/tools';

// All falsy values
const falsyValues: Falsy = false | '' | null | undefined | 0 | 0n | NaN;

if (isFalsy(value)) {
  // value is one of the falsy values
}
```

---

### Other Utilities

```typescript
import { delay, maskData, getTypeOf, createProxy } from '@belt/tools';

// Async delay
await delay(500); // Wait 500ms
await delay();    // Default 500ms

// Mask sensitive data for logging
const masked = maskData({
  password: 'secret123',
  email: 'user@example.com',
  nested: { token: 'abc123' },
});
// { password: 'String', email: 'String', nested: { token: 'String' } }

// Get type name
getTypeOf(null);           // 'Null'
getTypeOf(undefined);      // 'Undefined'
getTypeOf(new Date());     // 'Date'
getTypeOf({});             // 'Object'
getTypeOf([]);             // 'Array'
getTypeOf(NaN);            // 'NaN'

// Lazy initialization
const lazyConfig = createProxy(() => loadConfig());
// Config is only loaded on first access
```

/**
 * Keyboard Shortcuts Dialog
 *
 * Displays the list of keyboard shortcuts available in the MMS canvas.
 * Triggered by pressing '?' or from the Help menu.
 *
 * @see specs/006-user-interface.md Section 6.9.2
 */

import { Dialog, Classes, HTMLTable, Tag, Intent } from '@blueprintjs/core';
import { useUi } from '../store';
import type { UiSliceState } from '../store/slices/ui';

/**
 * Keyboard shortcut definition
 */
interface ShortcutDefinition {
  key: string;
  description: string;
  category: 'navigation' | 'zoom' | 'selection' | 'editing' | 'general';
}

/**
 * All keyboard shortcuts per spec 006.9.2
 */
const KEYBOARD_SHORTCUTS: ShortcutDefinition[] = [
  // Navigation shortcuts
  { key: 'Arrow keys', description: 'Pan canvas', category: 'navigation' },
  { key: 'Home', description: 'Go to today', category: 'navigation' },
  { key: 't', description: 'Go to today', category: 'navigation' },
  { key: 'Tab', description: 'Navigate between panels', category: 'navigation' },
  { key: 'Shift+Tab', description: 'Navigate between panels (reverse)', category: 'navigation' },

  // Zoom shortcuts
  { key: '+', description: 'Zoom in', category: 'zoom' },
  { key: '-', description: 'Zoom out', category: 'zoom' },
  { key: '1', description: 'Strategic view (12-year)', category: 'zoom' },
  { key: '2', description: 'Tactical-wide view (1-year)', category: 'zoom' },
  { key: '3', description: 'Tactical view (12-week)', category: 'zoom' },
  { key: '4', description: 'Operational view (4-week)', category: 'zoom' },
  { key: '5', description: 'Detail view (1-week)', category: 'zoom' },
  { key: 's', description: 'Strategic view', category: 'zoom' },
  { key: 'o', description: 'Operational view', category: 'zoom' },

  // Selection shortcuts
  { key: 'Enter', description: 'Activate selected element', category: 'selection' },
  { key: 'Space', description: 'Toggle selection', category: 'selection' },
  { key: 'Escape', description: 'Cancel drag / Close dialog / Deselect', category: 'selection' },

  // Editing shortcuts
  { key: 'l', description: 'Lock/unlock selected PM', category: 'editing' },
  { key: 'Delete', description: 'Cancel selected PM (with confirmation)', category: 'editing' },

  // General shortcuts
  { key: '?', description: 'Show keyboard shortcuts (this dialog)', category: 'general' },
];

/**
 * Category labels and order
 */
const CATEGORIES: { id: ShortcutDefinition['category']; label: string }[] = [
  { id: 'navigation', label: 'Navigation' },
  { id: 'zoom', label: 'Zoom & Views' },
  { id: 'selection', label: 'Selection' },
  { id: 'editing', label: 'Editing' },
  { id: 'general', label: 'General' },
];

/**
 * Shortcut key badge component
 */
function KeyBadge({ keyName }: { keyName: string }) {
  const parts = keyName.split('+');
  return (
    <span style={{ display: 'inline-flex', gap: '4px', alignItems: 'center' }}>
      {parts.map((part, index) => (
        <span key={index}>
          <Tag minimal style={{ fontFamily: 'monospace', fontWeight: 600, fontSize: '12px' }}>
            {part.trim()}
          </Tag>
          {index < parts.length - 1 && <span style={{ margin: '0 2px', color: '#5c7080' }}>+</span>}
        </span>
      ))}
    </span>
  );
}

/**
 * Shortcuts table for a category
 */
function ShortcutCategory({
  category,
  shortcuts,
}: {
  category: { id: string; label: string };
  shortcuts: ShortcutDefinition[];
}) {
  return (
    <div style={{ marginBottom: '20px' }}>
      <h4 style={{ margin: '0 0 8px 0', color: '#5c7080', fontSize: '13px', fontWeight: 600 }}>
        {category.label}
      </h4>
      <HTMLTable
        compact
        striped
        style={{ width: '100%', fontSize: '13px' }}
      >
        <tbody>
          {shortcuts.map((shortcut) => (
            <tr key={shortcut.key}>
              <td style={{ width: '140px', paddingRight: '16px' }}>
                <KeyBadge keyName={shortcut.key} />
              </td>
              <td>{shortcut.description}</td>
            </tr>
          ))}
        </tbody>
      </HTMLTable>
    </div>
  );
}

/**
 * Keyboard Shortcuts Dialog Component
 *
 * Displays all available keyboard shortcuts organized by category.
 * Uses @belt/tools state management for dialog visibility.
 */
export function KeyboardShortcutsDialog() {
  const { state: uiStateRaw, actions: uiActions } = useUi();
  const uiState = uiStateRaw as unknown as UiSliceState;

  const handleClose = () => {
    uiActions.hideKeyboardShortcutsDialog();
  };

  // Group shortcuts by category
  const shortcutsByCategory = CATEGORIES.map((category) => ({
    category,
    shortcuts: KEYBOARD_SHORTCUTS.filter((s) => s.category === category.id),
  })).filter(({ shortcuts }) => shortcuts.length > 0);

  return (
    <Dialog
      isOpen={uiState.keyboardShortcutsDialogOpen}
      onClose={handleClose}
      title="Keyboard Shortcuts"
      icon="key-command"
      style={{ width: '520px' }}
      data-testid="keyboard-shortcuts-dialog"
    >
      <div className={Classes.DIALOG_BODY} style={{ maxHeight: '60vh', overflowY: 'auto' }}>
        <p style={{ marginTop: 0, marginBottom: '20px', color: '#5c7080', fontSize: '13px' }}>
          These keyboard shortcuts help you navigate and interact with the PM schedule canvas efficiently.
        </p>

        {shortcutsByCategory.map(({ category, shortcuts }) => (
          <ShortcutCategory
            key={category.id}
            category={category}
            shortcuts={shortcuts}
          />
        ))}

        <div style={{ marginTop: '16px', padding: '12px', backgroundColor: '#f5f8fa', borderRadius: '4px' }}>
          <Tag intent={Intent.PRIMARY} minimal style={{ marginRight: '8px' }}>
            Tip
          </Tag>
          <span style={{ fontSize: '12px', color: '#5c7080' }}>
            Press <KeyBadge keyName="Escape" /> to close this dialog or any modal.
            Shortcuts are disabled when typing in input fields.
          </span>
        </div>
      </div>

      <div className={Classes.DIALOG_FOOTER}>
        <div className={Classes.DIALOG_FOOTER_ACTIONS}>
          <Tag minimal style={{ marginRight: 'auto', color: '#5c7080' }}>
            {uiState.shortcutsEnabled ? 'Shortcuts enabled' : 'Shortcuts disabled'}
          </Tag>
        </div>
      </div>
    </Dialog>
  );
}

/**
 * Export keyboard shortcuts constant for testing
 */
export { KEYBOARD_SHORTCUTS };

