   295→    },
   296→
   297→    clearError: (s) => {
   298→      const state = s as UiSliceState;
   299→      state.error = {
   300→        message: null,
   301→        code: null,
   302→        details: null,
   303→        timestamp: null,
   304→      };
   305→    },
   306→
   307→    // ==========================================================================
   308→    // Layout
   309→    // ==========================================================================
   310→
   311→    toggleSidebar: (s) => {
   312→      const state = s as UiSliceState;
   313→      state.sidebarCollapsed = !state.sidebarCollapsed;
   314→    },
   315→
   316→    setSidebarCollapsed: (s, collapsed: boolean) => {
