   371→      const state = s as UiSliceState;
   372→      const index = state.optimizerJobs.findIndex((j) => j.id === job.id);
   373→      if (index !== -1) {
   374→        state.optimizerJobs[index] = { ...state.optimizerJobs[index], ...job };
   375→      }
   376→    },
   377→
   378→    removeOptimizerJob: (s, jobId: string) => {
