/**
 * MMS Store Types
 *
 * TypeScript interfaces for UI state management.
 * These types align with the database schema but are optimized for frontend use.
 *
 * @see specs/006-user-interface.md Section 6.4
 */

// =============================================================================
// Fleet Domain Types
// =============================================================================

export type FitnessStatus = 'FIT' | 'RESTRICTED' | 'GROUNDED';
export type PmStatus = 'SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'CANCELLED' | 'DEFERRED';
export type TrackType = 'LIGHT' | 'HEAVY' | 'OVERHAUL' | 'STABLING';
export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';

/** Train entity optimized for UI rendering */
export interface Train {
  id: string;
  trainNumber: string;
  fleetId: string;
  fleetCode: string;
  currentMileageKm: number;
  targetMileageKm: number | null;
  fitnessStatus: FitnessStatus;
  fitnessNotes: string | null;
  currentDepotId: string | null;
  homeDepotId: string | null;
  displayColor: string;
  commissioningDate: string | null;
  updatedAt: string;
}

/** Fleet entity */
export interface Fleet {
  id: string;
  code: string;
  name: string;
  manufacturer: string | null;
  carsPerTrain: number;
  baseDepotId: string | null;
  displayColor: string;
}

/** Depot entity */
export interface Depot {
  id: string;
  code: string;
  name: string;
  timezone: string;
  latitude: number | null;
  longitude: number | null;
}

/** Route entity */
export interface Route {
  id: string;
  routeCode: string;
  name: string;
  expectedKmPerDay: number;
  requiredTrains: number;
  allowedFleetIds: string[];
}

// =============================================================================
// PM Schedule Types
// =============================================================================

/** PM type definition */
export interface PmType {
  id: string;
  fleetId: string;
  pmCode: string;
  description: string | null;
  intervalKm: number | null;
  intervalMonths: number | null;
  satisfiesCodes: string[];
  estimatedHours: number;
  trackType: TrackType;
}

/** PM schedule entry for canvas rendering */
export interface PmScheduleEntry {
  id: string;
  trainId: string;
  trainNumber: string;
  pmTypeId: string;
  pmCode: string;
  targetDate: string;
  status: PmStatus;
  constraintStart: string | null;
  constraintEnd: string | null;
  assignedTrackId: string | null;
  isLocked: boolean;
  lockedBy: string | null;
  lockedAt: string | null;
  scenarioId: string | null;
  estimatedHours: number;
  displayColor: string;
}

/** Drag-drop preview state */
export interface DragState {
  isDragging: boolean;
  pmId: string | null;
  sourceDate: string | null;
  targetDate: string | null;
  isValid: boolean;
  validationMessage: string | null;
  constraintViolations: ConstraintViolation[];
}

/** Constraint violation for drag preview */
export interface ConstraintViolation {
  type: 'COMPLIANCE_WINDOW' | 'TRACK_CONFLICT' | 'MATERIAL' | 'MAXIMO_LOCK' | 'SERVICE_DEMAND';
  severity: 'ERROR' | 'WARNING';
  message: string;
}

// =============================================================================
// Canvas Types
// =============================================================================

export type ZoomLevel = 'STRATEGIC' | 'TACTICAL_WIDE' | 'TACTICAL' | 'OPERATIONAL' | 'DETAIL';

/** Canvas viewport state */
export interface ViewportBounds {
  startDate: string;
  endDate: string;
  trainIds: string[];
}

/** Canvas layer visibility */
export interface LayerVisibility {
  pmBlocks: boolean;
  complianceWindows: boolean;
  manhourOverlay: boolean;
  driftOverlay: boolean;
  baselineShadow: boolean;
}

/** Canvas selection state */
export interface CanvasSelection {
  selectedPmIds: string[];
  selectedTrainIds: string[];
  isMultiSelect: boolean;
}

// =============================================================================
// Scenario Types
// =============================================================================

export type ScenarioStatus = 'ACTIVE' | 'PROMOTED' | 'EXPIRED' | 'DISCARDED';
export type DeltaType = 'PM_MOVE' | 'PM_ADD' | 'PM_REMOVE' | 'CAPACITY_CHANGE' | 'TRAIN_STATUS_CHANGE';

/** Scenario entity */
export interface Scenario {
  id: string;
  name: string;
  description: string | null;
  status: ScenarioStatus;
  forkedFromBaselineId: string | null;
  forkedFromScenarioId: string | null;
  createdBy: string;
  createdAt: string;
  updatedAt: string;
  expiresAt: string;
  changeCount: number;
}

/** Scenario delta (change event) */
export interface ScenarioDelta {
  id: string;
  scenarioId: string;
  sequenceNum: number;
  deltaType: DeltaType;
  entityId: string;
  oldValues: Record<string, unknown> | null;
  newValues: Record<string, unknown>;
  createdAt: string;
  createdBy: string;
}

// =============================================================================
// UI State Types
// =============================================================================

/** Filter state for train list */
export interface TrainFilters {
  fleetIds: string[];
  fitnessStatuses: FitnessStatus[];
  depotIds: string[];
  searchTerm: string;
}

/** Sort options */
export interface SortOptions {
  field: string;
  direction: 'asc' | 'desc';
}

/** Toast notification */
export interface Toast {
  id: string;
  type: 'success' | 'warning' | 'error' | 'info';
  title: string;
  message: string;
  duration: number;
  dismissible: boolean;
  createdAt: number;
}

/** Modal state */
export interface ModalState {
  isOpen: boolean;
  type: string | null;
  data: Record<string, unknown> | null;
}

/** Loading state for async operations */
export interface LoadingState {
  trains: boolean;
  pmSchedule: boolean;
  canvas: boolean;
  optimizer: boolean;
}

/** Error state */
export interface ErrorState {
  message: string | null;
  code: string | null;
  details: Record<string, unknown> | null;
  timestamp: number | null;
}

// =============================================================================
// Optimizer Types
// =============================================================================

export type OptimizerJobStatus = 'PENDING' | 'RUNNING' | 'COMPLETED' | 'FAILED' | 'CANCELLED';

/** Optimizer job tracking */
export interface OptimizerJob {
  id: string;
  type: 'RUN_ASSIGNMENT' | 'TACTICAL_SCHEDULE' | 'STRATEGIC_PLAN';
  status: OptimizerJobStatus;
  progress: number;
  startedAt: string | null;
  completedAt: string | null;
  error: string | null;
}

// =============================================================================
// Baseline & Drift Types
// =============================================================================

export type BaselineStatus = 'DRAFT' | 'PUBLISHED' | 'SUPERSEDED' | 'ARCHIVED';

/** Baseline for comparison */
export interface Baseline {
  id: string;
  name: string;
  version: string;
  status: BaselineStatus;
  baselineDate: string;
  totalPmCount: number;
  publishedAt: string | null;
  publishedBy: string | null;
}

/** Drift analysis result */
export interface DriftAnalysis {
  trainId: string;
  trainNumber: string;
  mileageDriftKm: number;
  mileageDriftPct: number;
  pmScheduleDriftDays: number;
  requiresReplan: boolean;
  severity: 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL';
}

