   927→    errors.push({ field: 'date', message: 'Date must be in YYYY-MM-DD format' });
   928→  }
   929→  if (!isValidUuid(data.fleetId)) {
   930→    errors.push({ field: 'fleetId', message: 'Invalid UUID format' });
   931→  }
   932→  if (!Array.isArray(data.trains) || data.trains.length === 0) {
