### 2. State Machines for Modal Open/Close

**UI State Machine Pattern (from the codebase):**
```typescript
import { createSlice, createMachine } from '@belt/tools';

// Define slice with modal reducers
const uiSlice = createSlice({
  id: 'ui',
  initial: {
    modal: {
      isOpen: false,
      type: null,
      data: null,
    },
  },
  reducers: {
    openModal: (s, payload: { type: string; data?: Record<string, unknown> }) => {
      s.modal = {
        isOpen: true,
        type: payload.type,
        data: payload.data ?? null,
      };
    },
    closeModal: (s) => {
      s.modal = {
        isOpen: false,
        type: null,
        data: null,
      };
    },
    updateModalData: (s, data: Record<string, unknown>) => {
      if (s.modal.isOpen) {
        s.modal.data = { ...s.modal.data, ...data };
      }
    },
  },
});

// Use in components
export function useUi() {
  return mmsMachine.useMachine('ui');
}

// React component example
function MyDialog() {
  const { state, actions } = useUi();

  return (
    <Dialog
      isOpen={state.modal.isOpen}
      onClose={() => actions.closeModal()}
    >
      <button onClick={() => actions.openModal({ type: 'CONFIRMATION', data: { id: '123' } })}>
        Open Dialog
      </button>
    </Dialog>
  );
}
```

